import React from 'react';
import { FaSignOutAlt, FaUser } from 'react-icons/fa';

const Navbar = ({ user, onLogout }) => {
  return (
    <nav className="fixed top-0 left-0 right-0 bg-white shadow-lg z-50 border-b-2 border-primary-light">
      <div className="container mx-auto px-6">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <div className="flex items-center">
            <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center mr-3">
              <span className="text-white font-bold">H</span>
            </div>
            <span className="text-xl font-bold text-gray-800">Helio</span>
          </div>

          {/* User info and logout */}
          {user && (
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <FaUser className="text-blue-500" />
                <span className="text-sm text-gray-600">
                  {user.profile?.first_name || user.username}
                </span>
              </div>
              {onLogout && (
                <button
                  onClick={onLogout}
                  className="flex items-center gap-1 px-3 py-1 text-red-600 hover:text-red-800 hover:bg-red-50 rounded transition-colors"
                  title="Logout"
                >
                  <FaSignOutAlt className="text-sm" />
                  <span className="text-sm">Logout</span>
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
